def _is_na(value) -> bool:
    return str(value).strip().lower() in _NA_VALS


def _load_card_csv(csv_path: Path, col: dict[str, str]) -> dict[int, dict]:
    if not csv_path.exists():
        return {}
    info: dict[int, dict] = {}
    with csv_path.open("r", encoding="utf-8-sig", newline="") as handle:
        reader = csv.DictReader(handle)
        for row in reader:
            try:
                card_id = int(row[col["id"]])
            except (ValueError, KeyError):
                continue
            if card_id not in info:
                info[card_id] = {
                    "name": row.get(col["name"], ""),
                    "hp": row.get(col["hp"], ""),
                    "type": row.get(col["type"], ""),
                    "weakness": row.get(col["weakness"], ""),
                    "resistance": row.get(col["resistance"], ""),
                    "retreat": row.get(col["retreat"], ""),
                    "stage": row.get(col["stage"], ""),
                    "rule": row.get(col["rule"], ""),
                    "attacks": [],
                    "card_effect": "",
                }
            move_str = str(row.get(col["move"], "")).strip()
            eff_str = str(row.get(col["effect"], "")).strip()
            if move_str and not _is_na(move_str):
                info[card_id]["attacks"].append(
                    {
                        "name": move_str,
                        "cost": row.get(col["cost"], ""),
                        "damage": row.get(col["damage"], ""),
                        "effect": "" if _is_na(eff_str) else eff_str,
                    }
                )
            elif eff_str and not _is_na(eff_str) and not info[card_id]["card_effect"]:
                info[card_id]["card_effect"] = eff_str
    return info


def load_card_info() -> dict[int, dict]:
    return _load_card_csv(ROOT / "JP_Card_Data.csv", _JP_COL)


def load_card_info_en() -> dict[int, dict]:
    return _load_card_csv(ROOT / "EN_Card_Data.csv", _EN_COL)


def load_card_names_en() -> dict[int, str]:
    if CARD_NAMES_EN:
        return CARD_NAMES_EN
    for card_id, info in load_card_info_en().items():
        name = str(info.get("name") or "").strip()
        if name:
            CARD_NAMES_EN[card_id] = name
    return CARD_NAMES_EN


def _existing_card_images(card_image_dir: str | Path, html_dir: Path | None = None) -> dict[int, str]:
    card_dir = Path(card_image_dir)
    if not card_dir.exists():
        return {}
    image_map: dict[int, str] = {}
    for image_path in card_dir.glob("*.png"):
        try:
            card_id = int(image_path.stem)
        except ValueError:
            continue
        if html_dir is not None:
            try:
                rel = os.path.relpath(image_path, html_dir)
            except ValueError:
                rel = str(image_path)
            image_map[card_id] = rel.replace(os.sep, "/")
        else:
            image_map[card_id] = str(image_path).replace(os.sep, "/")
    return image_map


def _resolve_card_image_map(output_path: str | Path) -> dict[int, str]:
    html_dir = Path(output_path).resolve().parent
    candidates = [
        html_dir / "card_images",
        ROOT / "card_images",
    ]
    merged: dict[int, str] = {}
    for candidate in candidates:
        merged.update(_existing_card_images(candidate, html_dir=html_dir))
    return merged


